func parseGeneratedReadtestBits128(input string) ([16]byte, error) {
	var raw [16]byte
	if strings.HasPrefix(input, "[") {
		literal := strings.TrimSuffix(strings.TrimPrefix(strings.TrimSpace(input), "["), "]")
		var hiText, loText string
		if strings.Contains(literal, ",") {
			parts := strings.SplitN(literal, ",", 2)
			hiText = strings.TrimSpace(parts[0])
			loText = strings.TrimSpace(parts[1])
		} else {
			compact := strings.ReplaceAll(literal, ",", "")
			if len(compact) > 32 {
				return raw, fmt.Errorf("readtest 128-bit hex literal %q exceeds 32 nybbles", input)
			}
			if len(compact) <= 16 {
				return raw, fmt.Errorf("readtest 128-bit hex literal %q does not contain high and low words", input)
			}
			hiText = compact[:16]
			loText = compact[16:]
		}
		if hiText == "" || loText == "" {
			return raw, fmt.Errorf("readtest 128-bit hex literal %q does not contain high and low words", input)
		}
		if len(hiText) > 16 || len(loText) > 16 {
			return raw, fmt.Errorf("readtest 128-bit hex literal %q exceeds 32 nybbles", input)
		}
		hi, err := strconv.ParseUint(hiText, 16, 64)
		if err != nil {
			return raw, err
		}
		lo, err := strconv.ParseUint(loText, 16, 64)
		if err != nil {
			return raw, err
		}
		binary.LittleEndian.PutUint64(raw[0:8], lo)
		binary.LittleEndian.PutUint64(raw[8:16], hi)
		return raw, nil
	}
	value, err := NewDecimal128BIDDirect(input)
	if err != nil {
		return raw, err
	}
	return value.ToBytes(), nil
}

func parseGeneratedReadtestHex(input string, bits int) (uint64, error) {
	trimmed := normalizeGeneratedReadtestHexLiteral(input)
	return strconv.ParseUint(trimmed, 16, bits)
}

func formatGeneratedReadtestBits128(raw [16]byte) string {
	lo := binary.LittleEndian.Uint64(raw[0:8])
	hi := binary.LittleEndian.Uint64(raw[8:16])
	return fmt.Sprintf("[%016x%016x]", hi, lo)
}

func normalizeGeneratedReadtestHexLiteral(input string) string {
	trimmed := strings.TrimSuffix(strings.TrimPrefix(strings.TrimSpace(input), "["), "]")
	return strings.ReplaceAll(trimmed, ",", "")
}

func parseGeneratedReadtestInt(input string) (int64, error) {
	return strconv.ParseInt(strings.TrimSpace(strings.TrimPrefix(input, "+")), 10, 64)
}

func parseGeneratedReadtestUint(input string) (uint64, error) {
	trimmed := strings.TrimSpace(strings.TrimPrefix(input, "+"))
	if value, err := strconv.ParseUint(trimmed, 10, 64); err == nil {
		return value, nil
	}
	signed, err := strconv.ParseInt(trimmed, 10, 64)
	if err != nil {
		return 0, err
	}
	return uint64(signed), nil
}

